import { useCallback } from 'react';
import axios from 'axios';

/**
 * Custom hook for managing AddCustomNotificationDrawer handlers
 * Extracts all handler logic to make the component more modular
 */
export const useAddCustomNotificationHandlers = ({
  onClose,
  onSuccess,
  onRefresh,
  formRef,
  setSaving,
  setToast,
  setDrawerOpen,
  setError,
  setConfirmationDialog
}) => {

  // Handle drawer close
  const handleCloseDrawer = useCallback(() => {
    setDrawerOpen(false);
    if (onClose) {
      onClose();
    }
  }, [onClose, setDrawerOpen]);

  // Handle cancel action
  const handleCancel = useCallback(() => {
    handleCloseDrawer();
  }, [handleCloseDrawer]);

  // Handle toast close
  const handleToastClose = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, [setToast]);

  // Fetch CSRF token and set CookieToken cookie - matching the working jQuery implementation
  const fetchCsrfToken = useCallback(async () => {
    try {
      const response = await fetch('/Tour/GetAntiForgeryToken');
      
      if (!response.ok) {
        console.error('CSRF token fetch failed with status:', response.status);
        return null;
      }
      
      const data = await response.json();
      
      // Extract the CSRF tokens from the response
      const csrfToken = data.token;
      const cookieToken = data.cookieToken;
      
      if (!csrfToken || !cookieToken) {
        console.error('No CSRF token in response:', data);
        return null;
      }
      
      // Set CookieToken cookie - required by ValidateHeaderAntiForgeryTokenAttribute
      document.cookie = `CookieToken=${cookieToken}; path=/`;
      
      return csrfToken;
    } catch (error) {
      console.error('Error fetching CSRF token:', error);
      return null;
    }
  }, []);

  // Handle save custom notification type
  const handleSaveClick = useCallback(async () => {
    try {
      setSaving(true);
      setError(null);

      // Get form data using the form component's exposed methods
      let formData = {};
      if (formRef.current && formRef.current.getFormData) {
        formData = formRef.current.getFormData();
      }

      // Use form's built-in validation (shows inline errors)
      if (formRef.current && formRef.current.validateForm) {
        const isValid = formRef.current.validateForm();
        if (!isValid) {
          setSaving(false);
          return; // Form validation will show inline errors
        }
      }

      // Prepare data for backend (matching NewNotificationTypeModel)
      const saveData = {
        newName: formData['NotificationTypeName'].trim()
      };

      // Fetch CSRF token and set CookieToken cookie - required by ValidateHeaderAntiForgeryTokenAttribute
      const token = await fetchCsrfToken();
      if (!token) {
        setToast({
          open: true,
          message: 'Security token not found. Please refresh the page and try again.',
          type: 'error',
          duration: 30000
        });
        setSaving(false);
        return;
      }

      // Make AJAX call to save the custom notification type
      // Use JSON format to match the controller's model binding and the old jQuery implementation
      const response = await axios.post('/Notification/CreateCustomNotificationType', saveData, {
        headers: {
          '__RequestVerificationToken': token
        }
      });

      const result = response.data;

      if (result.IsSuccess) {
        setToast({
          open: true,
          message: `Notification type "${saveData.newName}" saved successfully!`,
          type: 'success',
          duration: 30000
        });
        
        // Close drawer after successful save
        handleCloseDrawer();
        
        // Refresh the notification types dropdown
        if (onRefresh) {
          onRefresh();
        }
        
        // Call success callback if provided
        if (onSuccess) {
          onSuccess(result);
        }
      } else {
        setToast({
          open: true,
          message: `Error: ${result.Message || 'Failed to save notification type'}`,
          type: 'error',
          duration: 30000
        });
      }

    } catch (error) {
      console.error('Error saving notification type:', error);
      
      let errorMessage = 'Error saving notification type. ';
      if (error.message.includes('401')) {
        errorMessage += 'Authentication failed. Please refresh the page.';
      } else if (error.message.includes('403')) {
        errorMessage += 'Access denied. Please check your permissions.';
      } else if (error.message.includes('404')) {
        errorMessage += 'API endpoint not found.';
      } else if (error.message.includes('500')) {
        errorMessage += 'Server error. Please try again later.';
      } else {
        errorMessage += 'Please try again.';
      }
      
      setToast({
        open: true,
        message: errorMessage,
        type: 'error',
        duration: 30000
      });
      setError(error.message);
    } finally {
      setSaving(false);
    }
  }, [
    formRef,
    setSaving,
    setToast,
    setError,
    handleCloseDrawer,
    onSuccess,
    onRefresh,
    fetchCsrfToken
  ]);

  return {
    handleCloseDrawer,
    handleCancel,
    handleSaveClick,
    handleToastClose
  };
};
