import React, { forwardRef, useImperativeHandle, useState, useEffect } from 'react';
import { Box } from '@mui/material';
import FAWInput from '../../FAWInput';
import FAWTypography from '../../FAWTypography';
import '../styles/notifications.css';

const AddCustomNotificationForm = forwardRef(({
  onSave,
  onCancel,
  initialData = {},
  saving = false
}, ref) => {
  const [formData, setFormData] = useState({
    NotificationTypeName: initialData.NotificationTypeName || ''
  });

  const [errors, setErrors] = useState({});

  // Update form data when initialData changes
  useEffect(() => {
    setFormData({
      NotificationTypeName: initialData.NotificationTypeName || ''
    });
  }, [initialData]);

  // Expose methods to parent component
  useImperativeHandle(ref, () => ({
    getFormData: () => formData,
    validateForm: () => {
      const newErrors = {};
      
      if (!formData.NotificationTypeName || formData.NotificationTypeName.trim() === '') {
        newErrors.NotificationTypeName = 'Notification Type Name is required';
      } else if (formData.NotificationTypeName.trim().length > 100) {
        newErrors.NotificationTypeName = 'Notification Type Name must be 100 characters or less';
      }
      
      setErrors(newErrors);
      return Object.keys(newErrors).length === 0;
    },
    resetForm: () => {
      setFormData({
        NotificationTypeName: ''
      });
      setErrors({});
    }
  }));

  const handleInputChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
    
    // Clear error when user starts typing
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: ''
      }));
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (onSave) {
      onSave();
    }
  };

  return (
    <Box className="add-custom-notification-form" sx={{ p: 3, position: 'relative' }}>
      <form onSubmit={handleSubmit}>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
          <FAWInput
            name="NotificationTypeName"
            label="Notification Type Name"
            placeholder="Enter notification type name"
            value={formData.NotificationTypeName}
            onChange={(e) => handleInputChange('NotificationTypeName', e.target.value)}
            required
            fullWidth
            error={!!errors.NotificationTypeName}
            helperText={errors.NotificationTypeName}
            disabled={saving}
            inputProps={{ maxLength: 100 }}
            labelSx={{
              fontSize: '14px',
              fontWeight: 500
            }}
          />
        </Box>
      </form>
    </Box>
  );
});

AddCustomNotificationForm.displayName = 'AddCustomNotificationForm';

export default AddCustomNotificationForm;
